This is extremely dangerous! Fetching files from user-provided URLs is a classic Server-Side Request Forgery (SSRF) vector. Attackers can make your server request internal resources, cloud metadata endpoints, or other services it shouldn't access.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());

// VULNERABLE: Fetches any URL the user provides
app.post('/api/upload-from-url', async (req, res) => {
  const { imageUrl } = req.body;

  try {
    // Directly fetches user-controlled URL - DANGEROUS!
    const response = await axios.get(imageUrl, {
      responseType: 'arraybuffer'
    });

    const filename = `upload_${Date.now()}.jpg`;
    const filepath = path.join(__dirname, 'uploads', filename);

    fs.writeFileSync(filepath, response.data);

    res.json({ success: true, filename });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.listen(3000);
```

**Attack Payloads**:
```text
# Access AWS metadata endpoint to steal credentials
http://169.254.169.254/latest/meta-data/iam/security-credentials/

# Access internal services
http://localhost:6379/CONFIG%20GET%20*
http://internal-api.company.local/admin/users

# File protocol to read local files
file:///etc/passwd

# Cloud metadata endpoints
http://metadata.google.internal/computeMetadata/v1/
http://169.254.169.254/metadata/v1/
```

**Why This Is Dangerous**:
- Attackers can access cloud metadata endpoints and steal IAM credentials
- Internal services (Redis, Elasticsearch, internal APIs) become accessible
- Can be used to port scan internal networks
- May allow reading local files via file:// protocol
- Bypasses firewall rules since requests originate from trusted server

**SECURE VERSION**:

```javascript
const express = require('express');
const axios = require('axios');
const fs = require('fs');
const path = require('path');
const { URL } = require('url');
const dns = require('dns').promises;
const net = require('net');

const app = express();
app.use(express.json());

// Allowlist of permitted domains
const ALLOWED_DOMAINS = [
  'images.example.com',
  'cdn.trusted-service.com',
  'storage.googleapis.com'
];

// Blocked IP ranges (private, loopback, link-local, metadata)
const BLOCKED_IP_RANGES = [
  { start: '10.0.0.0', end: '10.255.255.255' },
  { start: '172.16.0.0', end: '172.31.255.255' },
  { start: '192.168.0.0', end: '192.168.255.255' },
  { start: '127.0.0.0', end: '127.255.255.255' },
  { start: '169.254.0.0', end: '169.254.255.255' },
  { start: '0.0.0.0', end: '0.255.255.255' }
];

function ipToLong(ip) {
  return ip.split('.').reduce((acc, octet) => (acc << 8) + parseInt(octet, 10), 0) >>> 0;
}

function isPrivateIP(ip) {
  const ipLong = ipToLong(ip);
  return BLOCKED_IP_RANGES.some(range => {
    const startLong = ipToLong(range.start);
    const endLong = ipToLong(range.end);
    return ipLong >= startLong && ipLong <= endLong;
  });
}

async function validateUrl(urlString) {
  // Parse and validate URL structure
  let parsedUrl;
  try {
    parsedUrl = new URL(urlString);
  } catch {
    throw new Error('Invalid URL format');
  }

  // Only allow HTTPS
  if (parsedUrl.protocol !== 'https:') {
    throw new Error('Only HTTPS URLs are allowed');
  }

  // Check against domain allowlist
  if (!ALLOWED_DOMAINS.includes(parsedUrl.hostname)) {
    throw new Error('Domain not in allowlist');
  }

  // Resolve DNS and check for private IPs (prevent DNS rebinding)
  const addresses = await dns.resolve4(parsedUrl.hostname);
  for (const ip of addresses) {
    if (isPrivateIP(ip)) {
      throw new Error('Resolved IP is in blocked range');
    }
  }

  return { parsedUrl, resolvedIP: addresses[0] };
}

app.post('/api/upload-from-url', async (req, res) => {
  const { imageUrl } = req.body;

  try {
    // Validate URL before fetching
    const { parsedUrl } = await validateUrl(imageUrl);

    const response = await axios.get(parsedUrl.href, {
      responseType: 'arraybuffer',
      maxRedirects: 0, // Prevent redirect-based bypass
      timeout: 10000,
      maxContentLength: 10 * 1024 * 1024 // 10MB limit
    });

    // Validate content type
    const contentType = response.headers['content-type'];
    if (!contentType || !contentType.startsWith('image/')) {
      throw new Error('Invalid content type');
    }

    const filename = `upload_${Date.now()}.jpg`;
    const filepath = path.join(__dirname, 'uploads', filename);

    fs.writeFileSync(filepath, response.data);

    res.json({ success: true, filename });
  } catch (error) {
    console.error(`URL fetch rejected: ${imageUrl} - ${error.message}`);
    res.status(400).json({ error: 'Invalid or disallowed URL' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Domain allowlist**: Only fetch from explicitly trusted domains
- **Protocol restriction**: HTTPS only, blocks file://, gopher://, dict:// schemes
- **IP validation**: Resolves DNS and blocks private/internal IP ranges
- **Redirect blocking**: maxRedirects: 0 prevents redirect-based bypasses
- **Content-Type validation**: Ensures response is actually an image

Excellent question! DNS rebinding is a sophisticated attack where an attacker controls a domain that initially resolves to a public IP (passing validation) but quickly changes to an internal IP before the actual HTTP request is made. This requires Time-of-Check to Time-of-Use (TOCTOU) protection.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const https = require('https');
const dns = require('dns').promises;
const { URL } = require('url');
const net = require('net');
const crypto = require('crypto');
const fs = require('fs').promises;
const path = require('path');

const app = express();
app.use(express.json());

// Configuration
const config = {
  allowedDomains: new Set([
    'images.example.com',
    'cdn.trusted-service.com'
  ]),
  maxFileSize: 10 * 1024 * 1024, // 10MB
  requestTimeout: 10000,
  uploadDir: path.join(__dirname, 'uploads'),
  allowedMimeTypes: new Set(['image/jpeg', 'image/png', 'image/gif', 'image/webp'])
};

// Metrics for monitoring
const metrics = {
  totalRequests: 0,
  blockedSSRF: 0,
  blockedDNSRebinding: 0,
  successfulUploads: 0
};

// Logger with structured output
const logger = {
  security: (event, data) => {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      level: 'SECURITY',
      event,
      ...data
    }));
  },
  info: (message, data = {}) => {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      level: 'INFO',
      message,
      ...data
    }));
  }
};

// Comprehensive IP validation
class IPValidator {
  static BLOCKED_RANGES = [
    // IPv4 private ranges
    { cidr: '10.0.0.0/8' },
    { cidr: '172.16.0.0/12' },
    { cidr: '192.168.0.0/16' },
    // Loopback
    { cidr: '127.0.0.0/8' },
    // Link-local
    { cidr: '169.254.0.0/16' },
    // Current network
    { cidr: '0.0.0.0/8' },
    // Broadcast
    { cidr: '255.255.255.255/32' },
    // Documentation ranges
    { cidr: '192.0.2.0/24' },
    { cidr: '198.51.100.0/24' },
    { cidr: '203.0.113.0/24' }
  ];

  static ipToLong(ip) {
    return ip.split('.').reduce((acc, octet) => (acc << 8) + parseInt(octet, 10), 0) >>> 0;
  }

  static cidrToRange(cidr) {
    const [ip, bits] = cidr.split('/');
    const mask = ~((1 << (32 - parseInt(bits))) - 1) >>> 0;
    const start = this.ipToLong(ip) & mask;
    const end = start | (~mask >>> 0);
    return { start, end };
  }

  static isBlocked(ip) {
    if (!net.isIPv4(ip)) {
      return true; // Block non-IPv4 for simplicity, extend for IPv6
    }

    const ipLong = this.ipToLong(ip);
    return this.BLOCKED_RANGES.some(range => {
      const { start, end } = this.cidrToRange(range.cidr);
      return ipLong >= start && ipLong <= end;
    });
  }
}

// DNS rebinding protection with pinning
class SafeURLFetcher {
  constructor() {
    this.dnsCache = new Map();
  }

  async resolveAndValidate(hostname) {
    // Resolve DNS
    let addresses;
    try {
      addresses = await dns.resolve4(hostname);
    } catch (error) {
      throw new Error(`DNS resolution failed: ${error.message}`);
    }

    if (!addresses || addresses.length === 0) {
      throw new Error('No DNS records found');
    }

    // Validate ALL resolved IPs (not just the first)
    for (const ip of addresses) {
      if (IPValidator.isBlocked(ip)) {
        throw new Error(`Blocked IP detected: ${ip}`);
      }
    }

    // Return first valid IP for pinning
    return addresses[0];
  }

  async fetch(urlString, options = {}) {
    // Parse URL
    let parsedUrl;
    try {
      parsedUrl = new URL(urlString);
    } catch {
      throw new Error('Invalid URL format');
    }

    // Protocol validation
    if (parsedUrl.protocol !== 'https:') {
      throw new Error('Only HTTPS allowed');
    }

    // Domain allowlist check
    if (!config.allowedDomains.has(parsedUrl.hostname)) {
      throw new Error('Domain not in allowlist');
    }

    // Block authentication in URL
    if (parsedUrl.username || parsedUrl.password) {
      throw new Error('Credentials in URL not allowed');
    }

    // Resolve and validate IP BEFORE making request
    const pinnedIP = await this.resolveAndValidate(parsedUrl.hostname);

    // Create custom agent that connects to pinned IP
    // This prevents DNS rebinding by using resolved IP directly
    return new Promise((resolve, reject) => {
      const requestOptions = {
        hostname: pinnedIP, // Connect to pinned IP
        port: 443,
        path: parsedUrl.pathname + parsedUrl.search,
        method: 'GET',
        timeout: options.timeout || config.requestTimeout,
        headers: {
          'Host': parsedUrl.hostname, // Original hostname for SNI/Host header
          'User-Agent': 'SafeURLFetcher/1.0'
        },
        // Re-validate IP on connection to prevent race conditions
        lookup: (hostname, opts, callback) => {
          // Always return our pinned IP
          if (IPValidator.isBlocked(pinnedIP)) {
            callback(new Error('IP validation failed during lookup'));
          } else {
            callback(null, pinnedIP, 4);
          }
        }
      };

      const req = https.request(requestOptions, (res) => {
        // Block redirects entirely
        if (res.statusCode >= 300 && res.statusCode < 400) {
          reject(new Error('Redirects not allowed'));
          return;
        }

        if (res.statusCode !== 200) {
          reject(new Error(`HTTP ${res.statusCode}`));
          return;
        }

        const chunks = [];
        let totalSize = 0;

        res.on('data', (chunk) => {
          totalSize += chunk.length;
          if (totalSize > config.maxFileSize) {
            req.destroy();
            reject(new Error('Response too large'));
          }
          chunks.push(chunk);
        });

        res.on('end', () => {
          resolve({
            data: Buffer.concat(chunks),
            headers: res.headers,
            pinnedIP
          });
        });
      });

      req.on('error', reject);
      req.on('timeout', () => {
        req.destroy();
        reject(new Error('Request timeout'));
      });

      req.end();
    });
  }
}

const fetcher = new SafeURLFetcher();

// Magic bytes validation for images
function validateImageMagicBytes(buffer) {
  const magicBytes = {
    'image/jpeg': [0xFF, 0xD8, 0xFF],
    'image/png': [0x89, 0x50, 0x4E, 0x47],
    'image/gif': [0x47, 0x49, 0x46, 0x38],
    'image/webp': [0x52, 0x49, 0x46, 0x46]
  };

  for (const [mimeType, bytes] of Object.entries(magicBytes)) {
    if (bytes.every((byte, i) => buffer[i] === byte)) {
      return mimeType;
    }
  }
  return null;
}

app.post('/api/upload-from-url', async (req, res) => {
  const requestId = crypto.randomUUID();
  metrics.totalRequests++;

  const { imageUrl } = req.body;
  const clientIP = req.ip;

  logger.info('URL upload request', { requestId, clientIP, imageUrl: imageUrl?.substring(0, 100) });

  if (!imageUrl || typeof imageUrl !== 'string') {
    return res.status(400).json({ error: 'imageUrl required' });
  }

  try {
    // Fetch with all protections
    const response = await fetcher.fetch(imageUrl, { timeout: 10000 });

    // Validate Content-Type header
    const contentType = response.headers['content-type']?.split(';')[0];
    if (!config.allowedMimeTypes.has(contentType)) {
      throw new Error('Invalid content type');
    }

    // Validate actual file content (magic bytes)
    const detectedType = validateImageMagicBytes(response.data);
    if (!detectedType) {
      logger.security('INVALID_FILE_CONTENT', { requestId, clientIP, imageUrl });
      throw new Error('File content does not match image format');
    }

    // Generate safe filename
    const ext = detectedType.split('/')[1];
    const filename = `${crypto.randomUUID()}.${ext}`;
    const filepath = path.join(config.uploadDir, filename);

    await fs.writeFile(filepath, response.data);

    metrics.successfulUploads++;
    logger.info('Upload successful', {
      requestId,
      filename,
      size: response.data.length,
      pinnedIP: response.pinnedIP
    });

    res.json({ success: true, filename });

  } catch (error) {
    // Categorize and log security events
    if (error.message.includes('Blocked IP') || error.message.includes('not in allowlist')) {
      metrics.blockedSSRF++;
      logger.security('SSRF_BLOCKED', {
        requestId,
        clientIP,
        imageUrl,
        reason: error.message
      });
    } else if (error.message.includes('DNS rebinding') || error.message.includes('IP validation failed')) {
      metrics.blockedDNSRebinding++;
      logger.security('DNS_REBINDING_BLOCKED', {
        requestId,
        clientIP,
        imageUrl,
        reason: error.message
      });
    }

    res.status(400).json({ error: 'URL processing failed' });
  }
});

// Metrics endpoint for monitoring
app.get('/metrics', (req, res) => {
  res.json({
    ...metrics,
    ssrfBlockRate: metrics.blockedSSRF / metrics.totalRequests || 0
  });
});

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

app.listen(3000, () => {
  logger.info('Server started', { port: 3000 });
});
```

**Defense in Depth Layers**:

1. **Input Validation Layer**:
```javascript
// Validate URL structure, protocol, and domain before any network operation
if (parsedUrl.protocol !== 'https:') throw new Error('Only HTTPS allowed');
if (!config.allowedDomains.has(parsedUrl.hostname)) throw new Error('Domain not allowed');
if (parsedUrl.username || parsedUrl.password) throw new Error('Credentials blocked');
```

2. **DNS Resolution with IP Pinning**:
```javascript
// Resolve DNS once, validate ALL IPs, then pin to prevent rebinding
const pinnedIP = await this.resolveAndValidate(parsedUrl.hostname);
// Connect directly to pinned IP with original Host header
requestOptions.hostname = pinnedIP;
requestOptions.headers['Host'] = parsedUrl.hostname;
```

3. **Content Validation Layer**:
```javascript
// Don't trust Content-Type header alone - validate actual file bytes
const detectedType = validateImageMagicBytes(response.data);
if (!detectedType) throw new Error('Invalid file content');
```

**Additional Protections**:
- **Zero redirect tolerance**: Redirects are completely blocked to prevent redirect-based SSRF bypasses
- **Response size limits**: Prevents memory exhaustion via large responses
- **Request timeouts**: Prevents resource exhaustion from slow responses
- **Structured security logging**: Every blocked request is logged with full context for SOC analysis
- **Metrics collection**: Track SSRF block rates for anomaly detection
- **Magic byte validation**: Prevents polyglot files that might exploit downstream processors
- **Randomized filenames**: Prevents path traversal and predictable file locations

**Monitoring Alerts to Configure**:
```text
1. Alert when metrics.blockedSSRF > 10 in 1 minute (potential attack)
2. Alert on any DNS_REBINDING_BLOCKED event (sophisticated attack)
3. Alert when SSRF block rate > 20% (possible enumeration)
4. Alert on repeated requests from same IP to blocked resources
```

No, fetching external resources during file processing is extremely dangerous and a common SSRF attack vector. Attackers embed malicious URLs in uploaded files (SVG, PDF, Office docs) that your server fetches during processing, allowing them to access internal networks and cloud metadata.

**VULNERABLE CODE**:

```java
import org.apache.batik.transcoder.TranscoderInput;
import org.apache.batik.transcoder.TranscoderOutput;
import org.apache.batik.transcoder.image.PNGTranscoder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import javax.servlet.http.HttpServletResponse;
import java.io.*;

@RestController
public class ImageUploadController {

    @PostMapping("/upload/svg")
    public String convertSvgToPng(@RequestParam("file") MultipartFile file,
                                   HttpServletResponse response) throws Exception {
        // VULNERABLE: No restrictions on external entity resolution
        PNGTranscoder transcoder = new PNGTranscoder();

        InputStream inputStream = file.getInputStream();
        TranscoderInput input = new TranscoderInput(inputStream);

        ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
        TranscoderOutput output = new TranscoderOutput(outputStream);

        // DANGEROUS: Batik will fetch ANY URL referenced in the SVG
        transcoder.transcode(input, output);

        // Save the converted image
        String outputPath = "/uploads/" + System.currentTimeMillis() + ".png";
        Files.write(Paths.get(outputPath), outputStream.toByteArray());

        return "Converted successfully: " + outputPath;
    }
}
```

**Attack Payload** (malicious SVG file):
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE svg [
  <!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <image xlink:href="http://169.254.169.254/latest/meta-data/iam/security-credentials/admin-role" />
  <text>&xxe;</text>
</svg>
```

**Why This Is Dangerous**:
- SVG files can contain `<image xlink:href>` pointing to internal URLs
- XML parsers resolve external entities (XXE) fetching arbitrary URLs
- Server makes requests to internal networks (169.254.169.254 for cloud metadata)
- Attackers extract AWS/GCP credentials, internal service data, or perform port scanning

**SECURE VERSION**:

```java
import org.apache.batik.transcoder.TranscoderInput;
import org.apache.batik.transcoder.TranscoderOutput;
import org.apache.batik.transcoder.image.PNGTranscoder;
import org.apache.batik.util.XMLResourceDescriptor;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import org.xml.sax.XMLReader;

import javax.xml.parsers.SAXParserFactory;
import java.io.*;
import java.nio.file.*;

@RestController
public class SecureImageUploadController {

    private static final long MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
    private static final Set<String> ALLOWED_TYPES = Set.of("image/svg+xml");

    @PostMapping("/upload/svg")
    public String convertSvgToPng(@RequestParam("file") MultipartFile file) 
            throws Exception {

        // 1. Validate file size
        if (file.getSize() > MAX_FILE_SIZE) {
            throw new IllegalArgumentException("File too large");
        }

        // 2. Validate content type
        String contentType = file.getContentType();
        if (contentType == null || !ALLOWED_TYPES.contains(contentType)) {
            throw new IllegalArgumentException("Invalid file type");
        }

        // 3. Create secure XML parser that blocks external entities
        SAXParserFactory factory = SAXParserFactory.newInstance();
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // 4. Configure Batik with restricted resource loading
        PNGTranscoder transcoder = new PNGTranscoder();

        // Block all external resource loading
        transcoder.addTranscodingHint(
            PNGTranscoder.KEY_ALLOWED_SCRIPT_TYPES, "");
        transcoder.addTranscodingHint(
            PNGTranscoder.KEY_EXECUTE_ONLOAD, Boolean.FALSE);

        InputStream inputStream = file.getInputStream();
        TranscoderInput input = new TranscoderInput(inputStream);

        ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
        TranscoderOutput output = new TranscoderOutput(outputStream);

        transcoder.transcode(input, output);

        String outputPath = "/uploads/" + java.util.UUID.randomUUID() + ".png";
        Files.write(Paths.get(outputPath), outputStream.toByteArray());

        return "Converted successfully";
    }
}
```

**Key Security Controls**:
- **Disable DTD/External Entities**: `disallow-doctype-decl` prevents XXE attacks entirely
- **Block External Resources**: Batik hints prevent fetching external URLs during rendering
- **File Validation**: Size and type checks prevent abuse
- **Randomized Output Names**: Prevents path traversal and enumeration

PDF processing is even more dangerous because PDFs support JavaScript, embedded files, and external resource loading. Libraries like Apache PDFBox and iText can be exploited for SSRF if not configured securely.

**PRODUCTION PATTERN**:

```java
import org.apache.pdfbox.Loader;
import org.apache.pdfbox.pdmodel.PDDocument;
import org.apache.pdfbox.pdmodel.PDDocumentCatalog;
import org.apache.pdfbox.pdmodel.interactive.action.PDAction;
import org.apache.pdfbox.pdmodel.interactive.action.PDActionURI;
import org.apache.pdfbox.rendering.PDFRenderer;
import org.apache.pdfbox.text.PDFTextStripper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.*;
import java.net.*;
import java.nio.file.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.*;

@RestController
public class SecurePdfController {

    private static final Logger logger = LoggerFactory.getLogger(SecurePdfController.class);
    private static final long MAX_PDF_SIZE = 25 * 1024 * 1024; // 25MB
    private static final int MAX_PAGES = 100;
    private static final int PROCESSING_TIMEOUT_SECONDS = 30;

    // Blocked URL patterns for SSRF prevention
    private static final List<Pattern> BLOCKED_PATTERNS = Arrays.asList(
        Pattern.compile("^https?://169\\.254\\..*"),           // AWS metadata
        Pattern.compile("^https?://metadata\\.google\\..*"),    // GCP metadata
        Pattern.compile("^https?://metadata\\.azure\\..*"),     // Azure metadata
        Pattern.compile("^https?://10\\..*"),                   // Private Class A
        Pattern.compile("^https?://172\\.(1[6-9]|2[0-9]|3[0-1])\\..*"), // Private Class B
        Pattern.compile("^https?://192\\.168\\..*"),            // Private Class C
        Pattern.compile("^https?://127\\..*"),                  // Localhost
        Pattern.compile("^https?://localhost.*"),               // Localhost
        Pattern.compile("^https?://\\[::1\\].*"),               // IPv6 localhost
        Pattern.compile("^file://.*"),                          // File protocol
        Pattern.compile("^gopher://.*"),                        // Gopher protocol
        Pattern.compile("^dict://.*")                           // Dict protocol
    );

    private final ExecutorService executor = Executors.newFixedThreadPool(4);

    @PostMapping("/upload/pdf")
    public PdfProcessingResult processPdf(
            @RequestParam("file") MultipartFile file,
            @RequestHeader("X-Request-ID") String requestId) {

        String uploadId = UUID.randomUUID().toString();
        logger.info("PDF upload started: uploadId={}, requestId={}, size={}, filename={}",
            uploadId, requestId, file.getSize(), sanitizeFilename(file.getOriginalFilename()));

        try {
            // Layer 1: Pre-processing validation
            validateUpload(file);

            // Layer 2: Process in isolated thread with timeout
            Future<PdfProcessingResult> future = executor.submit(() -> 
                processSecurely(file, uploadId));

            PdfProcessingResult result = future.get(PROCESSING_TIMEOUT_SECONDS, TimeUnit.SECONDS);

            logger.info("PDF processed successfully: uploadId={}, pages={}",
                uploadId, result.getPageCount());

            return result;

        } catch (TimeoutException e) {
            logger.error("PDF processing timeout: uploadId={}", uploadId);
            throw new ProcessingException("Processing timeout - file may be too complex");
        } catch (Exception e) {
            logger.error("PDF processing failed: uploadId={}, error={}", uploadId, e.getMessage());
            throw new ProcessingException("Failed to process PDF");
        }
    }

    private void validateUpload(MultipartFile file) {
        // Size check
        if (file.getSize() > MAX_PDF_SIZE) {
            throw new ValidationException("File exceeds maximum size of 25MB");
        }

        // Magic bytes check for PDF
        try (InputStream is = file.getInputStream()) {
            byte[] header = new byte[4];
            if (is.read(header) < 4 || !Arrays.equals(header, "%PDF".getBytes())) {
                throw new ValidationException("Invalid PDF file format");
            }
        } catch (IOException e) {
            throw new ValidationException("Cannot read file");
        }
    }

    private PdfProcessingResult processSecurely(MultipartFile file, String uploadId) 
            throws Exception {

        // Use temp file to avoid memory issues with large PDFs
        Path tempFile = Files.createTempFile("pdf_upload_", ".pdf");

        try {
            file.transferTo(tempFile.toFile());

            // PDFBox with security restrictions
            try (PDDocument document = Loader.loadPDF(tempFile.toFile())) {

                // Layer 3: Validate document structure
                validateDocumentSecurity(document, uploadId);

                // Layer 4: Check page count
                if (document.getNumberOfPages() > MAX_PAGES) {
                    throw new ValidationException("PDF exceeds maximum page count");
                }

                // Layer 5: Extract text safely (no external resource loading)
                PDFTextStripper stripper = new PDFTextStripper();
                stripper.setSortByPosition(true);
                String text = stripper.getText(document);

                // Scan extracted text for potential SSRF indicators
                scanForMaliciousContent(text, uploadId);

                // Layer 6: Generate thumbnail without external resources
                byte[] thumbnail = generateThumbnailSecurely(document);

                return new PdfProcessingResult(
                    uploadId,
                    document.getNumberOfPages(),
                    text.substring(0, Math.min(text.length(), 5000)),
                    thumbnail
                );
            }
        } finally {
            // Clean up temp file
            Files.deleteIfExists(tempFile);
        }
    }

    private void validateDocumentSecurity(PDDocument document, String uploadId) {
        PDDocumentCatalog catalog = document.getDocumentCatalog();

        // Check for JavaScript (can trigger external requests)
        if (catalog.getNames() != null && catalog.getNames().getJavaScript() != null) {
            logger.warn("PDF contains JavaScript - blocked: uploadId={}", uploadId);
            throw new SecurityException("PDFs with JavaScript are not allowed");
        }

        // Check OpenAction for URI actions
        PDAction openAction = catalog.getOpenAction();
        if (openAction instanceof PDActionURI) {
            String uri = ((PDActionURI) openAction).getURI();
            if (isBlockedUrl(uri)) {
                logger.warn("PDF contains blocked URI action: uploadId={}, uri={}", 
                    uploadId, sanitizeLogOutput(uri));
                throw new SecurityException("PDF contains blocked external references");
            }
        }

        // Check for embedded files
        if (catalog.getNames() != null && catalog.getNames().getEmbeddedFiles() != null) {
            logger.warn("PDF contains embedded files - blocked: uploadId={}", uploadId);
            throw new SecurityException("PDFs with embedded files are not allowed");
        }
    }

    private boolean isBlockedUrl(String url) {
        if (url == null) return false;

        String normalizedUrl = url.toLowerCase().trim();

        for (Pattern pattern : BLOCKED_PATTERNS) {
            if (pattern.matcher(normalizedUrl).matches()) {
                return true;
            }
        }

        // Additional check: resolve hostname to detect DNS rebinding
        try {
            URL parsedUrl = new URL(normalizedUrl);
            InetAddress address = InetAddress.getByName(parsedUrl.getHost());

            if (address.isLoopbackAddress() || 
                address.isSiteLocalAddress() || 
                address.isLinkLocalAddress()) {
                return true;
            }
        } catch (Exception e) {
            // If we can't parse/resolve, block it
            return true;
        }

        return false;
    }

    private void scanForMaliciousContent(String text, String uploadId) {
        // Scan for embedded URLs that might indicate SSRF attempts
        Pattern urlPattern = Pattern.compile("https?://[^\\s]+", Pattern.CASE_INSENSITIVE);
        java.util.regex.Matcher matcher = urlPattern.matcher(text);

        while (matcher.find()) {
            String foundUrl = matcher.group();
            if (isBlockedUrl(foundUrl)) {
                logger.warn("Suspicious URL in PDF content: uploadId={}, url={}",
                    uploadId, sanitizeLogOutput(foundUrl));
                // Log but don't block - it's just text content
            }
        }
    }

    private byte[] generateThumbnailSecurely(PDDocument document) throws Exception {
        PDFRenderer renderer = new PDFRenderer(document);

        // Render first page at low DPI for thumbnail
        BufferedImage image = renderer.renderImageWithDPI(0, 72);

        // Scale down to thumbnail size
        int thumbWidth = 200;
        int thumbHeight = (int) (image.getHeight() * (200.0 / image.getWidth()));

        BufferedImage thumbnail = new BufferedImage(thumbWidth, thumbHeight, 
            BufferedImage.TYPE_INT_RGB);
        thumbnail.getGraphics().drawImage(image, 0, 0, thumbWidth, thumbHeight, null);

        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ImageIO.write(thumbnail, "png", baos);

        return baos.toByteArray();
    }

    private String sanitizeFilename(String filename) {
        if (filename == null) return "unknown";
        return filename.replaceAll("[^a-zA-Z0-9._-]", "_");
    }

    private String sanitizeLogOutput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").substring(0, Math.min(input.length(), 200));
    }
}

class PdfProcessingResult {
    private String uploadId;
    private int pageCount;
    private String textPreview;
    private byte[] thumbnail;

    public PdfProcessingResult(String uploadId, int pageCount, String textPreview, byte[] thumbnail) {
        this.uploadId = uploadId;
        this.pageCount = pageCount;
        this.textPreview = textPreview;
        this.thumbnail = thumbnail;
    }

    public int getPageCount() { return pageCount; }
    public String getUploadId() { return uploadId; }
    public String getTextPreview() { return textPreview; }
    public byte[] getThumbnail() { return thumbnail; }
}

class ValidationException extends RuntimeException {
    public ValidationException(String message) { super(message); }
}

class ProcessingException extends RuntimeException {
    public ProcessingException(String message) { super(message); }
}
```

