**SECURE VERSION**:

```go
package main

import (
	"bytes"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"image"
	_ "image/gif"
	_ "image/jpeg"
	_ "image/png"
	"io"
	"log"
	"net/http"
	"path/filepath"
	"strings"

	"github.com/nfnt/resize"
)

const (
	maxFileSize     = 10 * 1024 * 1024 // 10MB
	allowedFormats  = "jpeg,jpg,png,gif"
)

var allowedMimeTypes = map[string]bool{
	"image/jpeg": true,
	"image/png":  true,
	"image/gif":  true,
}

func generateSafeFilename() string {
	b := make([]byte, 16)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func validateImageContent(data []byte) (string, error) {
	// Validate by actually decoding the image
	_, format, err := image.DecodeConfig(bytes.NewReader(data))
	if err != nil {
		return "", fmt.Errorf("invalid image format: %v", err)
	}

	// Verify format is allowed
	if !strings.Contains(allowedFormats, format) {
		return "", fmt.Errorf("unsupported format: %s", format)
	}

	return format, nil
}

func handleSecureUpload(w http.ResponseWriter, r *http.Request) {
	r.Body = http.MaxBytesReader(w, r.Body, maxFileSize)

	file, header, err := r.FormFile("image")
	if err != nil {
		http.Error(w, "Failed to read file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// Read file content into memory for validation
	var buf bytes.Buffer
	if _, err := io.Copy(&buf, file); err != nil {
		http.Error(w, "Failed to read file", http.StatusBadRequest)
		return
	}
	data := buf.Bytes()

	// Validate MIME type from content (not header)
	detectedMime := http.DetectContentType(data)
	if !allowedMimeTypes[detectedMime] {
		log.Printf("Rejected upload: invalid MIME %s from %s", detectedMime, r.RemoteAddr)
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	// Validate by decoding image (rejects SVG, XML, etc.)
	format, err := validateImageContent(data)
	if err != nil {
		log.Printf("Rejected upload: %v from %s", err, r.RemoteAddr)
		http.Error(w, "Invalid image", http.StatusBadRequest)
		return
	}

	// Process with Go's native image library (no external URLs)
	img, _, err := image.Decode(bytes.NewReader(data))
	if err != nil {
		http.Error(w, "Failed to process image", http.StatusInternalServerError)
		return
	}

	// Resize using pure Go library
	resized := resize.Resize(800, 0, img, resize.Lanczos3)

	// Generate safe filename (ignore user-provided name)
	safeFilename := generateSafeFilename() + "." + format

	log.Printf("Processed upload: %s -> %s from %s", 
		header.Filename, safeFilename, r.RemoteAddr)

	fmt.Fprintf(w, "Processed: %s", safeFilename)
	_ = resized // Store to disk/cloud storage
}

func main() {
	http.HandleFunc("/upload", handleSecureUpload)
	log.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **Content-based validation**: Detect MIME type from actual file content, not user-supplied headers
- **Native image processing**: Use Go's built-in image library which cannot process external URLs
- **Format whitelist**: Only allow safe raster formats (JPEG, PNG, GIF) - reject SVG, PDF, XML
- **Safe filename generation**: Ignore user-provided filenames to prevent path traversal

Document formats like PDF, DOCX, and XLSX are extremely dangerous because they can contain embedded URLs, macros, external references, and even JavaScript. The key is to process them in an isolated environment with network restrictions.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"
	"time"
)

type FileProcessor struct {
	maxFileSize     int64
	allowedTypes    map[string]FileTypeConfig
	sandboxPath     string
	processTimeout  time.Duration
	auditLogger     *log.Logger
}

type FileTypeConfig struct {
	MimeTypes    []string
	MagicBytes   [][]byte
	Processor    string
	MaxSize      int64
	Sanitize     bool
}

type ProcessingResult struct {
	OriginalHash  string `json:"original_hash"`
	ProcessedHash string `json:"processed_hash"`
	SafeFilename  string `json:"safe_filename"`
	FileType      string `json:"file_type"`
	Sanitized     bool   `json:"sanitized"`
}

func NewFileProcessor(sandboxPath string, auditLog *log.Logger) *FileProcessor {
	return &FileProcessor{
		maxFileSize:    50 * 1024 * 1024, // 50MB
		processTimeout: 30 * time.Second,
		sandboxPath:    sandboxPath,
		auditLogger:    auditLog,
		allowedTypes: map[string]FileTypeConfig{
			"pdf": {
				MimeTypes:  []string{"application/pdf"},
				MagicBytes: [][]byte{[]byte("%PDF")},
				Processor:  "pdf",
				MaxSize:    50 * 1024 * 1024,
				Sanitize:   true,
			},
			"docx": {
				MimeTypes:  []string{"application/vnd.openxmlformats-officedocument.wordprocessingml.document"},
				MagicBytes: [][]byte{[]byte("PK\x03\x04")}, // ZIP header
				Processor:  "docx",
				MaxSize:    25 * 1024 * 1024,
				Sanitize:   true,
			},
			"image": {
				MimeTypes:  []string{"image/jpeg", "image/png", "image/gif"},
				MagicBytes: [][]byte{
					[]byte("\xff\xd8\xff"),     // JPEG
					[]byte("\x89PNG"),          // PNG
					[]byte("GIF87a"), []byte("GIF89a"), // GIF
				},
				Processor: "image",
				MaxSize:   10 * 1024 * 1024,
				Sanitize:  false,
			},
		},
	}
}

// Validate file using magic bytes (not MIME type header)
func (fp *FileProcessor) detectFileType(data []byte) (string, error) {
	for typeName, config := range fp.allowedTypes {
		for _, magic := range config.MagicBytes {
			if len(data) >= len(magic) && bytes.Equal(data[:len(magic)], magic) {
				return typeName, nil
			}
		}
	}
	return "", fmt.Errorf("unsupported file type")
}

// Process PDF in isolated sandbox with network disabled
func (fp *FileProcessor) processPDFSandboxed(ctx context.Context, inputPath, outputPath string) error {
	// Use qpdf to flatten/sanitize PDF (removes JavaScript, external links)
	// Run in restricted environment
	cmd := exec.CommandContext(ctx, "qpdf",
		"--linearize",           // Optimize
		"--remove-unreferenced-resources=yes",
		"--flatten-annotations=all",
		"--remove-attachment=all",
		inputPath,
		outputPath,
	)

	// CRITICAL: Restrict network access using Linux namespaces
	cmd.SysProcAttr = &syscall.SysProcAttr{
		Cloneflags: syscall.CLONE_NEWNET, // New network namespace (no network)
	}

	// Restrict environment
	cmd.Env = []string{
		"PATH=/usr/bin",
		"HOME=/tmp",
		"TMPDIR=" + fp.sandboxPath,
	}

	// Set resource limits
	cmd.Dir = fp.sandboxPath

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return fmt.Errorf("PDF processing failed: %v, stderr: %s", err, stderr.String())
	}

	return nil
}

// Verify no outbound connections during processing
func (fp *FileProcessor) setupNetworkBlocker() error {
	// Block outbound connections to metadata services
	blockedIPs := []string{
		"169.254.169.254", // AWS/GCP metadata
		"100.100.100.200", // Alibaba metadata
		"192.0.0.192",     // Oracle metadata
	}

	for _, ip := range blockedIPs {
		// Use iptables or nftables to block
		cmd := exec.Command("iptables", "-A", "OUTPUT", "-d", ip, "-j", "DROP")
		if err := cmd.Run(); err != nil {
			log.Printf("Warning: Could not block %s: %v", ip, err)
		}
	}
	return nil
}

func (fp *FileProcessor) ProcessFile(ctx context.Context, data []byte, originalName, remoteAddr string) (*ProcessingResult, error) {
	// Generate content hash for audit
	hash := sha256.Sum256(data)
	originalHash := hex.EncodeToString(hash[:])

	// Detect actual file type from magic bytes
	fileType, err := fp.detectFileType(data)
	if err != nil {
		fp.auditLogger.Printf("REJECTED file=%s type=unknown hash=%s ip=%s",
			originalName, originalHash, remoteAddr)
		return nil, fmt.Errorf("unsupported file type")
	}

	config := fp.allowedTypes[fileType]

	// Check size limit for this type
	if int64(len(data)) > config.MaxSize {
		fp.auditLogger.Printf("REJECTED file=%s reason=size_exceeded hash=%s ip=%s",
			originalName, originalHash, remoteAddr)
		return nil, fmt.Errorf("file exceeds size limit")
	}

	// Create isolated temp directory
	sandboxDir, err := os.MkdirTemp(fp.sandboxPath, "process-")
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %v", err)
	}
	defer os.RemoveAll(sandboxDir)

	// Write input file with safe name
	inputPath := filepath.Join(sandboxDir, "input")
	if err := os.WriteFile(inputPath, data, 0600); err != nil {
		return nil, fmt.Errorf("failed to write input: %v", err)
	}

	outputPath := filepath.Join(sandboxDir, "output")

	// Process based on type with timeout
	processCtx, cancel := context.WithTimeout(ctx, fp.processTimeout)
	defer cancel()

	switch config.Processor {
	case "pdf":
		if err := fp.processPDFSandboxed(processCtx, inputPath, outputPath); err != nil {
			fp.auditLogger.Printf("FAILED file=%s type=%s error=%v hash=%s ip=%s",
				originalName, fileType, err, originalHash, remoteAddr)
			return nil, err
		}
	case "image":
		// Images processed with Go native library (no SSRF risk)
		if err := fp.processImageNative(data, outputPath); err != nil {
			return nil, err
		}
	default:
		return nil, fmt.Errorf("no processor for type: %s", fileType)
	}

	// Read processed file
	processedData, err := os.ReadFile(outputPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read output: %v", err)
	}

	processedHash := sha256.Sum256(processedData)
	safeFilename := hex.EncodeToString(hash[:8]) + "." + fileType

	// Audit successful processing
	fp.auditLogger.Printf("PROCESSED file=%s type=%s original_hash=%s processed_hash=%s safe_name=%s ip=%s",
		originalName, fileType, originalHash,
		hex.EncodeToString(processedHash[:]), safeFilename, remoteAddr)

	return &ProcessingResult{
		OriginalHash:  originalHash,
		ProcessedHash: hex.EncodeToString(processedHash[:]),
		SafeFilename:  safeFilename,
		FileType:      fileType,
		Sanitized:     config.Sanitize,
	}, nil
}

func (fp *FileProcessor) processImageNative(data []byte, outputPath string) error {
	// Use pure Go image processing - inherently safe from SSRF
	// Implementation similar to Turn 2's secure version
	return os.WriteFile(outputPath, data, 0600)
}

func main() {
	// Setup audit logger
	auditFile, _ := os.OpenFile("/var/log/upload-audit.log", 
		os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0600)
	auditLogger := log.New(auditFile, "", log.LstdFlags)

	processor := NewFileProcessor("/var/lib/sandbox", auditLogger)

	http.HandleFunc("/upload", func(w http.ResponseWriter, r *http.Request) {
		r.Body = http.MaxBytesReader(w, r.Body, processor.maxFileSize)

		file, header, err := r.FormFile("document")
		if err != nil {
			http.Error(w, "Failed to read file", http.StatusBadRequest)
			return
		}
		defer file.Close()

		var buf bytes.Buffer
		io.Copy(&buf, file)

		result, err := processor.ProcessFile(r.Context(), buf.Bytes(), 
			header.Filename, r.RemoteAddr)
		if err != nil {
			http.Error(w, "Processing failed", http.StatusBadRequest)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(result)
	})

	log.Fatal(http.ListenAndServe(":8080", nil))
}
