class UrlValidator {
    private array $blockedNetworks = [
        '127.0.0.0/8',      // Localhost
        '10.0.0.0/8',       // Private
        '172.16.0.0/12',    // Private
        '192.168.0.0/16',   // Private
        '169.254.0.0/16',   // Link-local (AWS/GCP metadata!)
        '100.64.0.0/10',    // Carrier-grade NAT
        '0.0.0.0/8',        // Current network
        '224.0.0.0/4',      // Multicast
        '240.0.0.0/4',      // Reserved
        'fd00::/8',         // IPv6 private
        '::1/128',          // IPv6 localhost
        'fe80::/10',        // IPv6 link-local
    ];

    private array $allowedSchemes = ['https'];
    private array $blockedHosts = [
        'metadata.google.internal',
        'metadata.azure.com',
        'localhost',
        '*.local'
    ];

    public function validate(string $url): ValidationResult {
        $parsed = parse_url($url);

        // Validate scheme
        $scheme = strtolower($parsed['scheme'] ?? '');
        if (!in_array($scheme, $this->allowedSchemes, true)) {
            return new ValidationResult(false, 'Invalid scheme: ' . $scheme);
        }

        $host = $parsed['host'] ?? '';

        // Check for blocked hosts
        foreach ($this->blockedHosts as $blockedHost) {
            if ($this->matchesPattern($host, $blockedHost)) {
                return new ValidationResult(false, 'Blocked host');
            }
        }

        // Resolve DNS and check IP
        $ips = gethostbynamel($host);
        if (!$ips) {
            return new ValidationResult(false, 'DNS resolution failed');
        }

        foreach ($ips as $ip) {
            if ($this->isBlockedIp($ip)) {
                return new ValidationResult(false, 'IP in blocked range');
            }
        }

        // Check for DNS rebinding by re-resolving
        usleep(100000); // 100ms delay
        $ipsRecheck = gethostbynamel($host);
        if ($ips !== $ipsRecheck) {
            return new ValidationResult(false, 'DNS rebinding detected');
        }

        return new ValidationResult(true);
    }

    private function isBlockedIp(string $ip): bool {
        foreach ($this->blockedNetworks as $cidr) {
            if ($this->ipInCidr($ip, $cidr)) {
                return true;
            }
        }
        return false;
    }

    private function ipInCidr(string $ip, string $cidr): bool {
        list($subnet, $bits) = explode('/', $cidr);

        if (filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_IPV4)) {
            $ip = ip2long($ip);
            $subnet = ip2long($subnet);
            $mask = -1 << (32 - (int)$bits);
            return ($ip & $mask) === ($subnet & $mask);
        }

        return false;
    }

    private function matchesPattern(string $host, string $pattern): bool {
        if (str_starts_with($pattern, '*.')) {
            $suffix = substr($pattern, 1);
            return str_ends_with($host, $suffix);
        }
        return $host === $pattern;
    }
}

class SvgSanitizer {
    private array $allowedElements = [
        'svg', 'g', 'path', 'rect', 'circle', 'ellipse',
        'line', 'polyline', 'polygon', 'text', 'tspan',
        'defs', 'clipPath', 'mask', 'linearGradient',
        'radialGradient', 'stop', 'use', 'symbol'
    ];

    private array $dangerousElements = [
        'script', 'foreignObject', 'iframe', 'object',
        'embed', 'link', 'style', 'image', 'animate',
        'set', 'animateTransform', 'animateMotion'
    ];

    public function sanitize(DOMDocument $doc): string {
        $xpath = new DOMXPath($doc);

        // Remove all dangerous elements
        foreach ($this->dangerousElements as $tagName) {
            $nodes = $xpath->query('//' . $tagName);
            foreach ($nodes as $node) {
                $node->parentNode->removeChild($node);
            }
        }

        // Remove event handlers and dangerous attributes
        $allElements = $xpath->query('//*');
        foreach ($allElements as $element) {
            $attributesToRemove = [];

            foreach ($element->attributes as $attr) {
                $name = strtolower($attr->name);

                // Block event handlers
                if (str_starts_with($name, 'on')) {
                    $attributesToRemove[] = $attr->name;
                }

                // Block href/xlink:href with javascript:
                if (in_array($name, ['href', 'xlink:href'])) {
                    if (preg_match('/^\s*javascript:/i', $attr->value)) {
                        $attributesToRemove[] = $attr->name;
                    }
                }
            }

            foreach ($attributesToRemove as $attrName) {
                $element->removeAttribute($attrName);
            }
        }

        return $doc->saveXML();
    }
}

class ValidationResult {
    public function __construct(
        private bool $valid,
        private string $reason = ''
    ) {}

    public function isValid(): bool { return $this->valid; }
    public function getReason(): string { return $this->reason; }
}

class SecurityException extends \Exception {}
