- **Network Isolation**: Process uploads in a sandboxed container with no network access to internal services

Processing uploaded files, especially SVG and XML-based formats, is extremely dangerous because these formats can contain embedded URLs and external entity references that trigger server-side requests.

**VULNERABLE CODE**:

```php
<?php
class ImageProcessor {
    private $uploadDir = '/var/www/uploads/';

    public function processUpload($file) {
        $filename = $file['name'];
        $tmpPath = $file['tmp_name'];
        $destPath = $this->uploadDir . $filename;

        // Move uploaded file
        move_uploaded_file($tmpPath, $destPath);

        // Process based on extension
        $ext = pathinfo($filename, PATHINFO_EXTENSION);

        if ($ext === 'svg') {
            // VULNERABLE: Loads SVG which may contain external references
            $svg = simplexml_load_file($destPath);
            return $this->processSvg($svg);
        }

        // VULNERABLE: ImageMagick can follow URLs in various formats
        $image = new Imagick($destPath);
        $image->thumbnailImage(200, 200, true);
        $image->writeImage($destPath . '_thumb.png');

        return ['status' => 'success', 'path' => $destPath];
    }

    private function processSvg($svg) {
        // Process SVG elements - follows any embedded URLs
        return $svg->asXML();
    }
}

// Usage
$processor = new ImageProcessor();
$result = $processor->processUpload($_FILES['image']);
echo json_encode($result);
?>
```

**Attack Payload** (malicious SVG file):
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE svg [
  <!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <image xlink:href="http://internal-service:8080/admin/secrets" />
  <text>&xxe;</text>
</svg>
```

**Alternative ImageMagick Attack** (MVG file):
```text
push graphic-context
viewbox 0 0 640 480
image over 0,0 0,0 'http://169.254.169.254/latest/meta-data/iam/security-credentials/admin'
pop graphic-context
```

**Why This Is Dangerous**:
- SVG files can contain XXE (XML External Entity) injections that fetch internal URLs
- ImageMagick processes URLs embedded in various image formats (SVG, MVG, MSL)
- The server makes requests to internal services or cloud metadata endpoints
- Attackers can steal AWS/GCP credentials, access internal APIs, or scan internal networks

**SECURE VERSION**:

```php
<?php
class SecureImageProcessor {
    private $uploadDir = '/var/www/uploads/';
    private $allowedMimeTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
    private $maxFileSize = 5242880; // 5MB

    public function __construct() {
        // Disable dangerous ImageMagick coders via policy.xml
        // This should also be done at system level
        putenv('MAGICK_CONFIGURE_PATH=/etc/ImageMagick-6/');
    }

    public function processUpload($file) {
        // Validate file upload
        if ($file['error'] !== UPLOAD_ERR_OK) {
            throw new Exception('Upload failed');
        }

        if ($file['size'] > $this->maxFileSize) {
            throw new Exception('File too large');
        }

        // Verify MIME type using actual file content, not extension
        $finfo = new finfo(FILEINFO_MIME_TYPE);
        $mimeType = $finfo->file($file['tmp_name']);

        if (!in_array($mimeType, $this->allowedMimeTypes, true)) {
            error_log("Rejected file upload with MIME type: {$mimeType}");
            throw new Exception('Invalid file type. Only JPEG, PNG, GIF, and WebP allowed.');
        }

        // Generate safe filename (no user input)
        $safeFilename = bin2hex(random_bytes(16)) . '.' . $this->getExtension($mimeType);
        $destPath = $this->uploadDir . $safeFilename;

        // Move to destination
        if (!move_uploaded_file($file['tmp_name'], $destPath)) {
            throw new Exception('Failed to save file');
        }

        // Process with GD library (safer than ImageMagick for untrusted files)
        $thumbnail = $this->createThumbnailWithGD($destPath, $mimeType);

        return [
            'status' => 'success',
            'filename' => $safeFilename,
            'thumbnail' => $thumbnail
        ];
    }

    private function createThumbnailWithGD($path, $mimeType) {
        // GD doesn't process URLs or external entities
        $image = match($mimeType) {
            'image/jpeg' => imagecreatefromjpeg($path),
            'image/png' => imagecreatefrompng($path),
            'image/gif' => imagecreatefromgif($path),
            'image/webp' => imagecreatefromwebp($path),
            default => throw new Exception('Unsupported format')
        };

        $width = imagesx($image);
        $height = imagesy($image);
        $thumbWidth = 200;
        $thumbHeight = (int)($height * ($thumbWidth / $width));

        $thumbnail = imagecreatetruecolor($thumbWidth, $thumbHeight);
        imagecopyresampled($thumbnail, $image, 0, 0, 0, 0, 
                          $thumbWidth, $thumbHeight, $width, $height);

        $thumbPath = str_replace('.', '_thumb.', $path);
        imagejpeg($thumbnail, $thumbPath, 85);

        imagedestroy($image);
        imagedestroy($thumbnail);

        return basename($thumbPath);
    }

    private function getExtension($mimeType) {
        return match($mimeType) {
            'image/jpeg' => 'jpg',
            'image/png' => 'png',
            'image/gif' => 'gif',
            'image/webp' => 'webp',
            default => 'bin'
        };
    }
}
?>
```

**Key Security Controls**:
- **Block SVG/XML uploads**: These formats can contain SSRF vectors; reject them entirely for untrusted uploads
- **Use GD instead of ImageMagick**: GD library doesn't process URLs or external entities
- **Validate MIME by content**: Use finfo to check actual file content, not just extension
- **Generate random filenames**: Never use user-supplied filenames which can cause path traversal

Supporting SVG uploads safely requires aggressive sanitization because SVG is XML-based and can contain scripts, external references, and SSRF vectors. Here's a production-ready approach with defense in depth.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

class SecureSvgProcessor {
    private string $uploadDir;
    private array $allowedElements = [
        'svg', 'g', 'path', 'rect', 'circle', 'ellipse', 'line', 
        'polyline', 'polygon', 'text', 'tspan', 'defs', 'use',
        'clipPath', 'mask', 'linearGradient', 'radialGradient', 'stop'
    ];

    private array $allowedAttributes = [
        'id', 'class', 'style', 'fill', 'stroke', 'stroke-width',
        'd', 'x', 'y', 'width', 'height', 'rx', 'ry', 'cx', 'cy',
        'r', 'points', 'transform', 'viewBox', 'xmlns', 'version',
        'offset', 'stop-color', 'stop-opacity', 'clip-path', 'mask'
    ];

    // Dangerous patterns that enable SSRF
    private array $dangerousPatterns = [
        '/<!ENTITY/i',
        '/<!DOCTYPE/i',
        '/SYSTEM\s+["\']http/i',
        '/SYSTEM\s+["\']file/i',
        '/PUBLIC\s+["\']http/i',
        '/xlink:href\s*=\s*["\'](?!#)/i',  // External xlink references
        '/href\s*=\s*["\'](?!#)[^"\']*(http|ftp|file|data|javascript)/i',
        '/<script/i',
        '/on\w+\s*=/i',  // Event handlers
        '/<foreignObject/i',
        '/<use[^>]+href\s*=\s*["\'](?!#)/i',  // External use references
        '/url\s*\(\s*["\']?(?!#)[^)]*\)/i',  // CSS url() with external refs
    ];

    private $logger;
    private $rateLimiter;

    public function __construct(string $uploadDir, $logger, $rateLimiter) {
        $this->uploadDir = rtrim($uploadDir, '/') . '/';
        $this->logger = $logger;
        $this->rateLimiter = $rateLimiter;

        // Disable external entity loading globally
        libxml_disable_entity_loader(true);
    }

    public function processUpload(array $file, string $userId): array {
        // Rate limiting per user
        if (!$this->rateLimiter->check($userId, 'svg_upload', 10, 3600)) {
            $this->logger->warning('Rate limit exceeded for SVG upload', [
                'user_id' => $userId,
                'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
            ]);
            throw new RateLimitException('Upload rate limit exceeded');
        }

        // Basic file validation
        $this->validateUpload($file);

        // Read raw content
        $content = file_get_contents($file['tmp_name']);
        if ($content === false || strlen($content) === 0) {
            throw new InvalidFileException('Unable to read uploaded file');
        }

        // Pre-sanitization pattern check (fast rejection)
        $this->checkDangerousPatterns($content, $userId);

        // Parse and sanitize SVG
        $sanitizedSvg = $this->sanitizeSvg($content);

        // Convert to PNG for storage (eliminates all XML risks)
        $pngPath = $this->convertToPng($sanitizedSvg, $userId);

        // Optionally store sanitized SVG
        $svgPath = $this->storeSanitizedSvg($sanitizedSvg, $userId);

        $this->logger->info('SVG processed successfully', [
            'user_id' => $userId,
            'original_size' => strlen($content),
            'sanitized_size' => strlen($sanitizedSvg)
        ]);

        return [
            'status' => 'success',
            'svg_path' => $svgPath,
            'png_path' => $pngPath
        ];
    }

    private function validateUpload(array $file): void {
        if ($file['error'] !== UPLOAD_ERR_OK) {
            throw new InvalidFileException('Upload error: ' . $file['error']);
        }

        if ($file['size'] > 1048576) { // 1MB max for SVG
            throw new InvalidFileException('SVG file too large');
        }

        // Check MIME type
        $finfo = new finfo(FILEINFO_MIME_TYPE);
        $mime = $finfo->file($file['tmp_name']);

        if (!in_array($mime, ['image/svg+xml', 'text/xml', 'application/xml', 'text/plain'], true)) {
            throw new InvalidFileException('Invalid SVG MIME type: ' . $mime);
        }
    }

    private function checkDangerousPatterns(string $content, string $userId): void {
        foreach ($this->dangerousPatterns as $pattern) {
            if (preg_match($pattern, $content)) {
                $this->logger->alert('Malicious SVG upload detected', [
                    'user_id' => $userId,
                    'pattern' => $pattern,
                    'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                    'content_preview' => substr($content, 0, 500)
                ]);
                throw new SecurityException('Potentially malicious SVG content detected');
            }
        }
    }

    private function sanitizeSvg(string $content): string {
        // Remove any XML declaration and DOCTYPE
        $content = preg_replace('/<\?xml[^>]*\?>/i', '', $content);
        $content = preg_replace('/<!DOCTYPE[^>]*>/i', '', $content);

        // Parse with libxml protections
        $oldValue = libxml_use_internal_errors(true);

        $dom = new DOMDocument();
        $dom->loadXML($content, 
            LIBXML_NONET |           // Disable network access
            LIBXML_NOENT |           // Don't substitute entities
            LIBXML_DTDLOAD |         // Don't load external DTD
            LIBXML_DTDATTR           // Don't default DTD attributes
        );

        libxml_use_internal_errors($oldValue);

        if ($dom->documentElement === null) {
            throw new InvalidFileException('Invalid SVG structure');
        }

        // Recursively sanitize all elements
        $this->sanitizeElement($dom->documentElement);

        // Remove all elements not in whitelist
        $this->removeDisallowedElements($dom);

        return $dom->saveXML($dom->documentElement);
    }

    private function sanitizeElement(DOMElement $element): void {
        // Remove dangerous attributes
        $attributesToRemove = [];

        foreach ($element->attributes as $attr) {
            $attrName = strtolower($attr->nodeName);
            $attrValue = $attr->nodeValue;

            // Check if attribute is allowed
            if (!in_array($attrName, $this->allowedAttributes, true)) {
                $attributesToRemove[] = $attr->nodeName;
                continue;
            }

            // Check attribute value for dangerous content
            if (preg_match('/(javascript|data:|http:|https:|ftp:|file:)/i', $attrValue)) {
                $attributesToRemove[] = $attr->nodeName;
            }
        }

        foreach ($attributesToRemove as $attrName) {
            $element->removeAttribute($attrName);
        }

        // Recursively process children
        foreach ($element->childNodes as $child) {
            if ($child instanceof DOMElement) {
                $this->sanitizeElement($child);
            }
        }
    }

    private function removeDisallowedElements(DOMDocument $dom): void {
        $xpath = new DOMXPath($dom);
        $nodesToRemove = [];

        // Find all elements
        foreach ($xpath->query('//*') as $node) {
            if (!in_array(strtolower($node->nodeName), $this->allowedElements, true)) {
                $nodesToRemove[] = $node;
            }
        }

        // Remove dangerous elements
        foreach ($nodesToRemove as $node) {
            if ($node->parentNode) {
                $node->parentNode->removeChild($node);
            }
        }
    }

    private function convertToPng(string $svgContent, string $userId): string {
        // Use Imagick with strict policy (configured at system level)
        // policy.xml should disable URL, MVG, MSL coders

        $safeFilename = bin2hex(random_bytes(16)) . '.png';
        $pngPath = $this->uploadDir . 'png/' . $safeFilename;

        // Write sanitized SVG to temp file
        $tempSvg = tempnam(sys_get_temp_dir(), 'svg_');
        file_put_contents($tempSvg, $svgContent);

        try {
            $imagick = new Imagick();
            $imagick->setOption('svg:xml-parse-huge', 'false');
            $imagick->readImage($tempSvg);
            $imagick->setImageFormat('png');
            $imagick->writeImage($pngPath);
            $imagick->destroy();
        } finally {
            @unlink($tempSvg);
        }

        return $safeFilename;
    }

    private function storeSanitizedSvg(string $svgContent, string $userId): string {
        $safeFilename = bin2hex(random_bytes(16)) . '.svg';
        $svgPath = $this->uploadDir . 'svg/' . $safeFilename;

        // Add security headers to SVG
        $secureContent = '<?xml version="1.0" encoding="UTF-8"?>' . "\n" . $svgContent;

        file_put_contents($svgPath, $secureContent);

        return $safeFilename;
    }
}

